package com.google.gson.internal;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.JsonElement;
import com.google.gson.internal.bind.TypeAdapters;
import com.google.gson.stream.JsonWriter;
import java.io.IOException;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

class StreamsTest {

  private JsonWriter mockWriter;
  private JsonElement mockElement;

  @BeforeEach
  void setUp() {
    mockWriter = mock(JsonWriter.class);
    mockElement = mock(JsonElement.class);
  }

  @Test
  void testWrite_callsTypeAdaptersJsonElementWrite() throws IOException {
    try (MockedStatic<TypeAdapters> typeAdaptersStatic = Mockito.mockStatic(TypeAdapters.class)) {
      var jsonElementAdapter = mock(TypeAdapters.JSON_ELEMENT.getClass());
      // Because JSON_ELEMENT is a static final field, we need to mock its write method directly.
      // Actually, JSON_ELEMENT is a static final TypeAdapter<JsonElement>, so we mock it directly.
      // But here we cannot mock a final static field directly, so we mock the static method write on JSON_ELEMENT.
      // Instead, we spy on TypeAdapters.JSON_ELEMENT to verify write call.

      // Spy on TypeAdapters.JSON_ELEMENT
      var spyAdapter = Mockito.spy(TypeAdapters.JSON_ELEMENT);

      // Replace the static field JSON_ELEMENT with spyAdapter via reflection
      var field = TypeAdapters.class.getDeclaredField("JSON_ELEMENT");
      field.setAccessible(true);
      var original = field.get(null);
      field.set(null, spyAdapter);

      // Call the focal method
      Streams.write(mockElement, mockWriter);

      // Verify write was called with correct params
      verify(spyAdapter).write(mockWriter, mockElement);

      // Restore original field value
      field.set(null, original);
    } catch (NoSuchFieldException | IllegalAccessException e) {
      fail("Reflection error: " + e.getMessage());
    }
  }

  @Test
  void testPrivateConstructor() throws Exception {
    var constructor = Streams.class.getDeclaredConstructor();
    constructor.setAccessible(true);
    var instance = constructor.newInstance();
    assertNotNull(instance);
  }
}
